\begin{proposition}[Bialynicki-Birula]
  \label{prop:BB_theory}
  \lean{VeryStableHiggsBundles.TODO.BialynickiBirula}
  \uses{def:semi_proj_variety, def:upward_flow, def:downward_flow, def:weight_decomp}
